fixed_code:
// Option A (stable): use Box<dyn Iterator> for naming
type EvenNumbers = Box<dyn Iterator<Item = i32>>;

fn evens_up_to(n: i32) -> EvenNumbers {
    Box::new((0..n).filter(|x| x % 2 == 0))
}

fn double_evens_up_to(n: i32) -> EvenNumbers {
    Box::new((0..n).filter(|x| x % 2 == 0).map(|x| x * 2))
}

// Option B (stable since Rust 1.75): RPITIT or just different return types
// fn evens(n: i32) -> impl Iterator<Item = i32> { (0..n).filter(|x| x % 2 == 0) }

fn main() {
    for x in evens_up_to(10) {
        println!("{}", x);
    }
    for x in double_evens_up_to(6) {
        println!("{}", x);
    }
}

