// Stable option A: type alias for a boxed trait object (heap-allocated, dynamic dispatch)
type Handler = Box<dyn Fn(&str) -> Result<(), String>>;

fn register(name: &str, handler: Handler) {
    println!("registering {}", name);
    handler(name).unwrap();
}

// Stable option B: generic function with a trait bound (no heap allocation, monomorphised)
fn register_static<F>(name: &str, handler: F)
where
    F: Fn(&str) -> Result<(), String>,
{
    println!("registering {}", name);
    handler(name).unwrap();
}

fn main() {
    register("test", Box::new(|s| {
        println!("handling (boxed) {}", s);
        Ok(())
    }));

    register_static("test2", |s| {
        println!("handling (static) {}", s);
        Ok(())
    });
}

