// This example compiles correctly — showing the correct pattern.
// A common mistake is expecting type aliases to create NEW types:
// type Meters = f64;
// type Seconds = f64;
// fn speed(m: Meters, s: Seconds) -> f64 { m / s }
// speed(5.0_f64, 10.0_f64); // no error — aliases are transparent, not newtypes
// To get type safety, use a newtype struct instead.

fixed_code:
use std::collections::HashMap;

#[derive(Debug)]
struct MyError(String);

// Type alias — transparent, purely for readability
type DataMap = HashMap<String, Vec<Option<i32>>>;
type DataResult = Result<DataMap, MyError>;

// Newtype pattern — creates a genuinely distinct type for type-safe units
#[derive(Debug, Clone, Copy, PartialEq, PartialOrd)]
struct Meters(f64);

#[derive(Debug, Clone, Copy, PartialEq, PartialOrd)]
struct Seconds(f64);

fn speed(distance: Meters, time: Seconds) -> f64 {
    distance.0 / time.0
}

trait Loader {
    fn load(&self) -> DataResult;
}

struct FileLoader;
impl Loader for FileLoader {
    fn load(&self) -> DataResult { Ok(HashMap::new()) }
}

fn main() {
    let fl = FileLoader;
    match fl.load() {
        Ok(m) => println!("keys: {}", m.len()),
        Err(e) => println!("error: {:?}", e),
    }
    // speed(Seconds(10.0), Meters(5.0)); // compile error: wrong argument order
    println!("speed: {}", speed(Meters(100.0), Seconds(9.58)));
}

