pub trait Reports {
    // Goal: return an iterator without exposing the concrete type
    // This doesn't compile — associated types with impl Trait need RPITIT or GATs
    type Iter = impl Iterator<Item = String>;
    fn report_lines(&self) -> Self::Iter;
}

pub struct Weekly {
    data: Vec<String>,
}

impl Reports for Weekly {
    type Iter = impl Iterator<Item = String>;
    fn report_lines(&self) -> Self::Iter {
        self.data.iter().map(|s| format!("[weekly] {}", s))
    }
}

fn main() {
    let r = Weekly { data: vec![String::from("item1")] };
    for line in r.report_lines() {
        println!("{}", line);
    }
}

fixed_code:
// Stable: RPITIT (Return Position impl Trait in Trait) — stable since Rust 1.75
pub trait Reports {
    fn report_lines(&self) -> impl Iterator<Item = String> + '_;
}

pub struct Weekly {
    data: Vec<String>,
}

impl Reports for Weekly {
    fn report_lines(&self) -> impl Iterator<Item = String> + '_ {
        self.data.iter().map(|s| format!("[weekly] {}", s))
    }
}

pub struct Daily {
    entries: Vec<String>,
}

impl Reports for Daily {
    fn report_lines(&self) -> impl Iterator<Item = String> + '_ {
        self.entries.iter().map(|s| format!("[daily] {}", s))
    }
}

fn print_report(r: &impl Reports) {
    for line in r.report_lines() {
        println!("{}", line);
    }
}

fn main() {
    print_report(&Weekly { data: vec![String::from("item1")] });
    print_report(&Daily { entries: vec![String::from("note1")] });
}

