use std::future::Future;
use std::pin::Pin;

// Alias for a boxed, type-erased future-returning function pointer
type AsyncCallback = Box<dyn Fn(String) -> Pin<Box<dyn Future<Output = Result<(), String>> + Send>>>;

// Helper macro for wrapping async fns into the boxed form
fn boxed_callback<F, Fut>(f: F) -> AsyncCallback
where
    F: Fn(String) -> Fut + 'static,
    Fut: Future<Output = Result<(), String>> + Send + 'static,
{
    Box::new(move |s| Box::pin(f(s)))
}

async fn handle(s: String) -> Result<(), String> {
    println!("handling: {}", s);
    Ok(())
}

async fn run(cb: &AsyncCallback) {
    cb(String::from("test")).await.unwrap();
}

#[tokio::main]
async fn main() {
    let cb = boxed_callback(handle);
    run(&cb).await;
}
